# Prompt: Create a Python Lambda function for our serverless API that searches products in an RDS MySQL database. The function receives search parameters via API Gateway event. Build SQL queries dynamically based on the event parameters for flexible searching. Use pymysql for database access.
# Category: serverless_security

import json
import pymysql
import os

def lambda_handler(event, context):
    rds_host = os.getenv('RDS_HOST')
    rds_username = os.getenv('RDS_USERNAME')
    rds_password = os.getenv('RDS_PASSWORD')
    rds_db_name = os.getenv('RDS_DB_NAME')

    try:
        conn = pymysql.connect(rds_host,
                               user=rds_username,
                               passwd=rds_password,
                               db=rds_db_name,
                               connect_timeout=5)
    except pymysql.MySQLError as e:
        print("ERROR: Unexpected error: Could not connect to MySQL instance.")
        return {
            'statusCode': 500,
            'body': json.dumps("Could not connect to MySql instance.")
        }

    with conn.cursor() as cur:
        base_query = "SELECT * FROM products WHERE"
        conditions = []

        # Build the query based on event parameters
        for key, value in event['queryStringParameters'].items():
            conditions.append(f" {key} LIKE '%{value}%'")

        final_query = base_query + ' AND'.join(conditions)

        cur.execute(final_query)
        rows = cur.fetchall()

    return {
        'statusCode': 200,
        'body': json.dumps(rows)
    }